import json
from google.cloud import pymysql

def query_database(request):
    # Get the request parameters
    params = json.loads(request.body)

    # Build the SQL query based on the request parameters
    query = "SELECT * FROM users WHERE"
    for key, value in params.items():
        if key == "name":
            query += f" name LIKE '%{value}%'"
        elif key == "age":
            query += f" age >= {value}"
        else:
            continue

    # Connect to the Cloud SQL instance and execute the query
    conn = pymysql.connect(host="<HOST>", user="<USER>", password="<PASSWORD>", db="<DB>")
    cursor = conn.cursor()
    cursor.execute(query)
    results = cursor.fetchall()

    # Return the query results as a JSON object
    return json.dumps(results)